  function loadCatalog() { if(cfg.mockMode && cfg.mockCatalog){var catalog=cfg.mockCatalog;if(new URLSearchParams(window.location.search).get('qa')==='tabs'){catalog=Object.assign({},catalog,{tabs:[{slug:'crystal',label:'Crystals'},{slug:'accessory',label:'Accessories'},{slug:'shaped-stones',label:'Shaped stones'},{slug:'charms',label:'Charms'},{slug:'limited',label:'Limited'}]});}return Promise.resolve(catalog);}return fetch((cfg.restUrl||'/wp-json/ew-t17/v1/')+'catalog').then(function(r){if(!r.ok)throw Error('The material catalog is unavailable.');return r.json();}); }
  function officialDesignId() { var fromConfig=Number(cfg.officialDesignId||0); if(Number.isInteger(fromConfig)&&fromConfig>0)return fromConfig; try { var fromUrl=Number(new URLSearchParams(window.location.search).get('t17_design')||0); return Number.isInteger(fromUrl)&&fromUrl>0?fromUrl:0; } catch(e) { return 0; } }
  function importOfficialDesign() { var id=officialDesignId(); if(!id)return Promise.resolve(false); var request;if(cfg.mockMode){var fixture=cfg.mockOfficialDesigns&&cfg.mockOfficialDesigns[id];if(!fixture)return Promise.resolve(false);request=Promise.resolve({ok:true,data:fixture});}else{request=fetch((cfg.restUrl||'/wp-json/ew-t17/v1/')+'official-design/'+encodeURIComponent(id)).then(function(r){return r.json().then(function(data){return {ok:r.ok,data:data};});});} return request.then(function(result){if(!result.ok)throw Error(result.data.message||'The official design is unavailable.'); var recipe=result.data.recipe||{}, sequence=Array.isArray(recipe.sequence)?recipe.sequence:[]; if(!sequence.length||sequence.some(function(item){return !item||!variants.has(item.variant_id);})){throw Error('The official design references unavailable materials.');} state.sequence=sequence.map(function(item){var next={variant_id:item.variant_id,size_mm:Number(variants.get(item.variant_id).size_mm)};if(item.orientation)next.orientation=item.orientation;return next;});state.scatter=[];state.assembled=true;state.wrist=Number(recipe.target_wrist_cm)||16; state.fit=recipe.fit_preference||'regular'; state.packaging=recipe.packaging||{}; state.quote=result.data.quote||null; localStorage.removeItem('ew-t17-ui-draft'); render(); notice('Official design imported.'); return true; }).catch(function(error){notice(error.message,true); return false;}); }
  loadCatalog().then(function(data){state.catalog=data;allVariants().forEach(function(v){variants.set(v.id,v);}); if(officialDesignId()){return importOfficialDesign().then(function(imported){if(!imported){restore();if(!state.sequence.length&&cfg.mockMode&&Array.isArray(cfg.mockInitialSequence)){state.sequence=cfg.mockInitialSequence.filter(function(item){return item&&variants.has(item.variant_id);}).map(function(item){return {variant_id:item.variant_id,size_mm:Number(variants.get(item.variant_id).size_mm),orientation:item.orientation||''};});state.scatter=[];state.selectedIndex=state.sequence.length?0:null;}quote();render();}});} restore();if(!state.sequence.length&&cfg.mockMode&&Array.isArray(cfg.mockInitialSequence)){state.sequence=cfg.mockInitialSequence.filter(function(item){return item&&variants.has(item.variant_id);}).map(function(item){return {variant_id:item.variant_id,size_mm:Number(variants.get(item.variant_id).size_mm),orientation:item.orientation||''};});state.scatter=[];state.selectedIndex=state.sequence.length?0:null;}quote();render();return false;}).catch(function(){notice('The material catalog is unavailable.',true);});
